            const expectedTotal = 9.98;
            if (total === expectedTotal) {  // Using triple-equals operator
                document.getElementById('broken-comparison-result').textContent = 'Comparison: Passed (but it might fail due to floating-point errors)';
                document.getElementById('broken-comparison-result').className = 'success';
